@import url('https://fonts.googleapis.com/css2?family=Cormorant+Garamond:ital,wght@0,300;0,400;0,500;0,600;1,300;1,400;1,500&family=DM+Sans:ital,opsz,wght@0,9..40,300;0,9..40,400;0,9..40,500;1,9..40,400&display=swap');

@tailwind base;
@tailwind components;
@tailwind utilities;

/* ─── Reset & Base ─── */
*, *::before, *::after {
  box-sizing: border-box;
}

html {
  scroll-behavior: smooth;
  -webkit-font-smoothing: antialiased;
  -moz-osx-font-smoothing: grayscale;
}

body {
  margin: 0;
  background-color: #fdfcfb;
  color: #1a1a1a;
  font-family: 'DM Sans', system-ui, sans-serif;
  overflow-x: hidden;
}

/* ─── Display Typography ─── */
.font-display {
  font-family: 'Cormorant Garamond', Georgia, serif;
  font-weight: 400;
}

.display-intro {
  font-size: clamp(1rem, 1.5vw, 1.375rem);
  line-height: 1.15;
  letter-spacing: -0.02em;
  font-style: italic;
  color: #8a553a;
}

/* ─── Micro-interaction Foundations ─── */
.tactile-hover {
  transition: transform 0.6s cubic-bezier(0.22, 1, 0.36, 1),
              opacity 0.4s ease;
}

.tactile-hover:hover {
  transform: translateY(-4px);
}

.tactile-hover:active {
  transition-duration: 0.1s;
  transform: translateY(-1px);
}

/* ─── Ink-line divider ─── */
.ink-line {
  height: 1px;
  background: linear-gradient(90deg, transparent, #d4d4d4 20%, #d4d4d4 80%, transparent);
  border: none;
}

.ink-line--accent {
  background: linear-gradient(90deg, transparent, #c4734f 30%, #c4734f 70%, transparent);
  opacity: 0.4;
}

/* ─── Clay orb — abstract pottery visualization ─── */
.clay-orb {
  position: relative;
  width: 100%;
  padding-top: 110%;
  border-radius: 50% 50% 48% 52% / 52% 48% 52% 48%;
  overflow: hidden;
  transition: border-radius 0.8s cubic-bezier(0.22, 1, 0.36, 1);
}

.clay-orb::before {
  content: '';
  position: absolute;
  inset: 0;
  border-radius: inherit;
  transition: border-radius 0.8s cubic-bezier(0.22, 1, 0.36, 1);
}

.tactile-hover:hover .clay-orb {
  border-radius: 48% 52% 52% 48% / 48% 52% 48% 52%;
}

.tactile-hover:hover .clay-orb::before {
  border-radius: inherit;
}

/* ─── Form variation: bowl ─── */
.form-bowl {
  border-radius: 45% 55% 50% 50% / 60% 60% 40% 40%;
}

/* ─── Form variation: plate ─── */
.form-plate {
  border-radius: 50% / 52% 48% 52% 48%;
}

/* ─── Form variation: vase ─── */
.form-vase {
  border-radius: 40% 60% 55% 45% / 48% 48% 52% 52%;
}

/* ─── Glaze shimmer effect ─── */
.glaze-shimmer {
  position: absolute;
  top: -50%;
  left: -50%;
  width: 200%;
  height: 200%;
  background: radial-gradient(ellipse at 35% 30%, rgba(255,255,255,0.18) 0%, transparent 55%);
  pointer-events: none;
  transition: all 0.8s cubic-bezier(0.22, 1, 0.36, 1);
  mix-blend-mode: soft-light;
}

.tactile-hover:hover .glaze-shimmer {
  top: -40%;
  left: -35%;
  opacity: 0.7;
}

/* ─── Texture noise overlay for clay forms ─── */
.clay-texture {
  position: absolute;
  inset: 0;
  opacity: 0.06;
  background-image: url("data:image/svg+xml,%3Csvg viewBox='0 0 256 256' xmlns='http://www.w3.org/2000/svg'%3E%3Cfilter id='noise'%3E%3CfeTurbulence type='fractalNoise' baseFrequency='0.9' numOctaves='4' stitchTiles='stitch'/%3E%3C/filter%3E%3Crect width='100%25' height='100%25' filter='url(%23noise)'/%3E%3C/svg%3E");
  background-size: 128px 128px;
  pointer-events: none;
}

/* ─── Specular highlight (subtle rim light on form) ─── */
.specular-highlight {
  position: absolute;
  top: 8%;
  right: 12%;
  width: 35%;
  height: 25%;
  border-radius: 50%;
  background: radial-gradient(ellipse, rgba(255,255,255,0.22) 0%, transparent 70%);
  pointer-events: none;
  transform: rotate(-15deg);
}

/* ─── Stagger animation delays ─── */
.stagger-1 { animation-delay: 0.1s; }
.stagger-2 { animation-delay: 0.2s; }
.stagger-3 { animation-delay: 0.3s; }
.stagger-4 { animation-delay: 0.4s; }
.stagger-5 { animation-delay: 0.5s; }
.stagger-6 { animation-delay: 0.6s; }

/* ─── Scroll-triggered visibility ─── */
.reveal {
  opacity: 0;
  transform: translateY(24px);
  transition: opacity 0.8s cubic-bezier(0.22, 1, 0.36, 1),
              transform 0.8s cubic-bezier(0.22, 1, 0.36, 1);
}

.reveal.visible {
  opacity: 1;
  transform: translateY(0);
}

/* ─── Navigation link underline animation ─── */
.nav-link {
  position: relative;
}

.nav-link::after {
  content: '';
  position: absolute;
  bottom: -2px;
  left: 0;
  width: 0;
  height: 1px;
  background-color: #c4734f;
  transition: width 0.5s cubic-bezier(0.22, 1, 0.36, 1);
}

.nav-link:hover::after {
  width: 100%;
}

/* ─── Label badge ─── */
.label-badge {
  display: inline-block;
  font-family: 'DM Sans', system-ui, sans-serif;
  font-size: 0.5625rem;
  font-weight: 500;
  letter-spacing: 0.18em;
  text-transform: uppercase;
  color: #a66e4a;
  border: 1px solid #e6d8c9;
  padding: 0.3em 0.9em;
  border-radius: 100px;
  transition: all 0.4s cubic-bezier(0.22, 1, 0.36, 1);
}

.tactile-hover:hover .label-badge {
  background-color: #a66e4a;
  color: #faf7f4;
  border-color: #a66e4a;
}

/* ─── Price display ─── */
.price-tag {
  font-family: 'Cormorant Garamond', Georgia, serif;
  font-size: 1.5rem;
  font-weight: 400;
  letter-spacing: -0.01em;
  color: #404040;
  transition: color 0.4s ease;
}

.tactile-hover:hover .price-tag {
  color: #c4734f;
}

/* ─── Grain overlay for warmth ─── */
.grain-overlay {
  position: fixed;
  top: -50%;
  left: -50%;
  width: 200%;
  height: 200%;
  pointer-events: none;
  z-index: 9999;
  opacity: 0.025;
  background-image: url("data:image/svg+xml,%3Csvg viewBox='0 0 512 512' xmlns='http://www.w3.org/2000/svg'%3E%3Cfilter id='noise'%3E%3CfeTurbulence type='fractalNoise' baseFrequency='0.65' numOctaves='3' stitchTiles='stitch'/%3E%3C/filter%3E%3Crect width='100%25' height='100%25' filter='url(%23noise)'/%3E%3C/svg%3E");
}

/* ─── Cursor follow glow (decorative accent) ─── */
.cursor-glow {
  position: fixed;
  width: 320px;
  height: 320px;
  border-radius: 50%;
  background: radial-gradient(circle, rgba(196,115,79,0.06) 0%, transparent 70%);
  pointer-events: none;
  z-index: 0;
  transition: transform 0.15s ease-out;
  will-change: transform;
}

/* ─── Selection color ─── */
::selection {
  background-color: #e6d8c9;
  color: #4e3025;
}

/* ─── Smooth scrollbar ─── */
::-webkit-scrollbar {
  width: 6px;
}

::-webkit-scrollbar-track {
  background: #f2ebe3;
}

::-webkit-scrollbar-thumb {
  background: #d4bfa6;
  border-radius: 3px;
}

::-webkit-scrollbar-thumb:hover {
  background: #b78762;
}

